namespace Contoso.Orders.Tests;

[TestClass]
public sealed class OrderServiceTests
{
    private readonly OrderService _service;

    public OrderServiceTests()
    {
        _service = new OrderService();
    }

    private static List<OrderItem> CreateItems(params (string name, decimal price, int qty)[] items) =>
        items.Select(i => new OrderItem { ProductName = i.name, Price = i.price, Quantity = i.qty }).ToList();

    // --- CreateOrder: success paths ---

    [TestMethod]
    public void CreateOrder_WithValidItems_ReturnsOrderWithCorrectTotal()
    {
        // Arrange
        var items = CreateItems(("Widget", 10.00m, 2), ("Gadget", 25.00m, 1));

        // Act
        var order = _service.CreateOrder("cust-1", items);

        // Assert
        Assert.AreEqual(45.00m, order.Total);
        Assert.AreEqual("cust-1", order.CustomerId);
        Assert.IsNotNull(order.Id);
        Assert.AreEqual(2, order.Items.Count);
    }

    [TestMethod]
    public void CreateOrder_WithSingleItem_SetsCorrectTotal()
    {
        var items = CreateItems(("Widget", 7.50m, 4));

        var order = _service.CreateOrder("cust-2", items);

        Assert.AreEqual(30.00m, order.Total);
    }

    [TestMethod]
    public void CreateOrder_SetsCreatedAtToApproximatelyNow()
    {
        var before = DateTime.UtcNow;
        var order = _service.CreateOrder("cust-1", CreateItems(("A", 1m, 1)));
        var after = DateTime.UtcNow;

        Assert.IsTrue(order.CreatedAt >= before && order.CreatedAt <= after,
            $"CreatedAt {order.CreatedAt} should be between {before} and {after}.");
    }

    [TestMethod]
    public void CreateOrder_AssignsUniqueIds()
    {
        var items = CreateItems(("A", 1m, 1));

        var order1 = _service.CreateOrder("cust-1", items);
        var order2 = _service.CreateOrder("cust-1", items);

        Assert.AreNotEqual(order1.Id, order2.Id);
    }

    // --- CreateOrder: validation / error paths ---

    [TestMethod]
    public void CreateOrder_WithNullCustomerId_ThrowsArgumentNullException()
    {
        var ex = Assert.ThrowsExactly<ArgumentNullException>(
            () => _service.CreateOrder(null!, CreateItems(("A", 1m, 1))));

        Assert.AreEqual("customerId", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_WithNullItems_ThrowsArgumentNullException()
    {
        var ex = Assert.ThrowsExactly<ArgumentNullException>(
            () => _service.CreateOrder("cust-1", null!));

        Assert.AreEqual("items", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_WithEmptyItems_ThrowsInvalidOperationException()
    {
        Assert.ThrowsExactly<InvalidOperationException>(
            () => _service.CreateOrder("cust-1", []));
    }

    // --- CreateOrder: total calculation edge cases ---

    [TestMethod]
    [DataRow(0.00, 5, 0.00, DisplayName = "Zero price")]
    [DataRow(10.00, 0, 0.00, DisplayName = "Zero quantity")]
    public void CreateOrder_WithZeroPriceOrQuantity_CalculatesTotalCorrectly(
        double price, int quantity, double expectedTotal)
    {
        var items = CreateItems(("Item", (decimal)price, quantity));

        var order = _service.CreateOrder("cust-1", items);

        Assert.AreEqual((decimal)expectedTotal, order.Total);
    }

    // --- GetOrder ---

    [TestMethod]
    public void GetOrder_WithExistingId_ReturnsMatchingOrder()
    {
        var created = _service.CreateOrder("cust-1", CreateItems(("A", 5m, 1)));

        var found = _service.GetOrder(created.Id);

        Assert.IsNotNull(found);
        Assert.AreEqual(created.Id, found.Id);
        Assert.AreEqual(created.CustomerId, found.CustomerId);
    }

    [TestMethod]
    public void GetOrder_WithNonExistentId_ReturnsNull()
    {
        var result = _service.GetOrder("does-not-exist");

        Assert.IsNull(result);
    }

    // --- GetOrdersByCustomer ---

    [TestMethod]
    public void GetOrdersByCustomer_WithMultipleOrders_ReturnsAllForCustomer()
    {
        _service.CreateOrder("cust-A", CreateItems(("X", 1m, 1)));
        _service.CreateOrder("cust-A", CreateItems(("Y", 2m, 1)));
        _service.CreateOrder("cust-B", CreateItems(("Z", 3m, 1)));

        var orders = _service.GetOrdersByCustomer("cust-A");

        Assert.AreEqual(2, orders.Count);
        Assert.IsTrue(orders.All(o => o.CustomerId == "cust-A"));
    }

    [TestMethod]
    public void GetOrdersByCustomer_WithNoOrders_ReturnsEmptyList()
    {
        var orders = _service.GetOrdersByCustomer("no-orders");

        Assert.AreEqual(0, orders.Count);
    }
}

